function Shop() {
  const [searchTerm, setSearchTerm] = useState('');
  const [cartCount, setCartCount] = useState(0);

  const syncCartCount = () => {
    const savedCart = JSON.parse(localStorage.getItem(CART_KEY) || '[]');
    setCartCount(savedCart.reduce((total, item) => total + item.quantity, 0));
  };

  useEffect(() => {
    syncCartCount();
    window.addEventListener('storage', syncCartCount);
    return () => window.removeEventListener('storage', syncCartCount);
  }, []);

  const addToCart = (product) => {
    const savedCart = JSON.parse(localStorage.getItem(CART_KEY) || '[]');
    const existingItem = savedCart.find((item) => item.id === product.id);

    const updatedCart = existingItem
      ? savedCart.map((item) => (item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item))
      : [...savedCart, { ...product, quantity: 1 }];

    localStorage.setItem(CART_KEY, JSON.stringify(updatedCart));
    syncCartCount();
  };

  const filteredProducts = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return products;

    return products.filter((product) =>
      [product.title, product.category].some((value) =>
        value.toLowerCase().includes(query),
      ),
    );
  }, [searchTerm]);

  return (
    <section className="page-card">
      <p className="eyebrow">Shop</p>
      <h1>Cricket-inspired gear and accessories</h1>
      <p className="lede">Browse the local collection and add items directly to your cart.</p>
      <p className="tag">Items in cart: {cartCount}</p>
      <input
        className="form-card"
        type="search"
        value={searchTerm}
        onChange={(event) => setSearchTerm(event.target.value)}
        placeholder="Search for cricket gear, hats, shoes, or accessories"
        style={{ marginTop: '12px' }}
      />
      <p style={{ marginTop: '12px' }}>
        <a className="btn btn-primary" href="/cart" target="_blank" rel="noopener noreferrer">Open cart</a>
      </p>
      <div className="product-grid">
        {filteredProducts.map((product) => (
          <article className="product-card" key={product.id}>
            <img src={product.image} alt={product.title} />
            <h2>{product.title}</h2>
            <p className="tag">{product.category}</p>
            <p className="price">$ {product.price}</p>
            <button className="btn btn-primary" type="button" onClick={() => addToCart(product)}>Add to cart</button>
          </article>
        ))}
      </div>
    </section>
  );
}

export default Shop;
